import{_ as e,o as i,c as t,a1 as r}from"./chunks/framework.BX4nIuL2.js";const u=JSON.parse('{"title":"AI 应用基础课程","description":"","frontmatter":{},"headers":[],"relativePath":"courses/ai-basics/index.md","filePath":"courses/ai-basics/index.md"}'),l={name:"courses/ai-basics/index.md"};function o(s,a,n,d,c,p){return i(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-应用基础课程" tabindex="-1">AI 应用基础课程 <a class="header-anchor" href="#ai-应用基础课程" aria-label="Permalink to &quot;AI 应用基础课程&quot;">​</a></h1><p>本课程旨在帮助学习者掌握如何将现代人工智能（LLM、视觉模型及生成式 AI）应用到工科研发与日常创新流程中。</p><h2 id="课程概述" tabindex="-1">课程概述 <a class="header-anchor" href="#课程概述" aria-label="Permalink to &quot;课程概述&quot;">​</a></h2><p>AI 正在重构我们与机器、代码和设计的交互方式。本课程不仅介绍 AI 的基本理论，更侧重于工程实践中的具体落地应用。</p><h3 id="核心板块" tabindex="-1">核心板块 <a class="header-anchor" href="#核心板块" aria-label="Permalink to &quot;核心板块&quot;">​</a></h3><ol><li><p><strong>大语言模型与 Prompt 工程</strong></p><ul><li>掌握结构化 Prompt 的设计原则。</li><li>在硬件选型、代码编写和技术文档撰写中高效使用 AI 助手。</li></ul></li><li><p><strong>生成式 AI 与工业设计</strong></p><ul><li>使用 Stable Diffusion、Midjourney 等生成工具辅助产品外观与 CMF 设计。</li><li>从文本概念快速转化为高质量视觉效果图。</li></ul></li><li><p><strong>智能体 (Agents) 开发入门</strong></p><ul><li>理解 Agent 架构体系（感知、规划、记忆与执行）。</li><li>编写简易的硬件部署/测试辅助 Agent。</li></ul></li></ol><hr><h2 id="实践研讨与划词共创" tabindex="-1">实践研讨与划词共创 <a class="header-anchor" href="#实践研讨与划词共创" aria-label="Permalink to &quot;实践研讨与划词共创&quot;">​</a></h2><p>本课程的所有学习材料均支持 <strong>Hypothesis 划词批注</strong> 讨论。请在阅读过程中高亮关键句，并与社群里的其他创客共同探讨 AI 落地应用的最佳实践。</p>',9)])])}const _=e(l,[["render",o]]);export{u as __pageData,_ as default};
